const items = $input.all();
const normalizePath = (value) => {
  const decoded = decodeURIComponent(String(value || ''));
  return decoded.startsWith('/') ? decoded : `/${decoded}`;
};
return items
  .filter((item) => item.json.type === 'file' && typeof item.json.path === 'string' && item.json.path.toLowerCase().endsWith('.md'))
  .map((item) => ({
    json: {
      ...item.json,
      source_path: normalizePath(item.json.path),
      source_folder: '/Notes/Blog Articles/1-Review/',
      reviewed_folder: '/Notes/Blog Articles/2-Reviewed/'
    }
  }));

const sourcePath = $json.source_path;
const fileName = sourcePath.split('/').pop();
const buffer = await helpers.getBinaryDataBuffer(0, 'data');
const raw = buffer.toString('utf8');
const match = raw.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
const frontmatterRaw = match ? match[1] : '';
const body = (match ? match[2] : raw).trim();

const metadata = {};
let currentKey = null;
for (const line of frontmatterRaw.split(/\r?\n/)) {
  if (!line.trim()) continue;
  const listMatch = line.match(/^\s*-\s+(.*)$/);
  if (listMatch && currentKey) {
    if (!Array.isArray(metadata[currentKey])) metadata[currentKey] = [];
    metadata[currentKey].push(listMatch[1].trim().replace(/^['"]|['"]$/g, ''));
    continue;
  }
  const keyMatch = line.match(/^([A-Za-z0-9_]+):\s*(.*)$/);
  if (!keyMatch) continue;
  const [, key, rawValue] = keyMatch;
  currentKey = key;
  const value = rawValue.trim();
  if (value === '') {
    metadata[key] = [];
    continue;
  }
  if (value === 'null') {
    metadata[key] = null;
    continue;
  }
  metadata[key] = value.replace(/^['"]|['"]$/g, '');
}

const slugify = (value) => value
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .replace(/-{2,}/g, '-');

const title = metadata.title || body.split(/\r?\n/).find((line) => line.startsWith('# '))?.replace(/^#\s+/, '') || fileName.replace(/\.md$/i, '');
const slug = metadata.slug && metadata.slug.trim() ? metadata.slug.trim() : slugify(title);
const reviewRound = Number(metadata.review_round || 0) || 0;
const reviewedPath = `/Notes/Blog Articles/2-Reviewed/${fileName}`;

return {
  json: {
    source_path: sourcePath,
    reviewed_path: reviewedPath,
    file_name: fileName,
    raw_markdown: raw,
    frontmatter: metadata,
    body_markdown: body,
    title,
    slug,
    review_round: reviewRound,
    created_at: metadata.created_at || '',
    updated_at: metadata.updated_at || '',
    source_type: metadata.source_type || 'note',
    source_path_meta: metadata.source_path || '/Notes/Blog Articles/1-Review/',
    published_json_path: metadata.published_json_path || ''
  }
};

const source = $('Parse Frontmatter And Body').item.json;
const payload = {
  title: source.title,
  slug: source.slug,
  frontmatter: source.frontmatter,
  body_markdown: source.body_markdown
};

return {
  json: {
    ...source,
    codex_payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
};

const source = $('Build Codex Payload').item.json;
const stdout = String($json.stdout || '').trim();
if (!stdout) {
  throw new Error('Codex wrapper did not return stdout.');
}

let ai;
try {
  ai = JSON.parse(stdout);
} catch (error) {
  throw new Error(`Codex wrapper returned invalid JSON: ${error.message}`);
}

const now = new Date().toISOString();
const reviewRound = (Number(source.review_round || 0) || 0) + 1;
const slug = (source.slug || ai.slug || '').trim();
const tags = Array.isArray(ai.tags) ? ai.tags : Array.isArray(source.frontmatter.tags) ? source.frontmatter.tags : [];

const lines = [];
lines.push('---');
lines.push(`title: "${String(ai.title || source.title).replace(/"/g, '\\"')}"`);
lines.push(`slug: "${String(slug).replace(/"/g, '\\"')}"`);
lines.push('status: reviewed');
lines.push('tags:');
for (const tag of tags) lines.push(`  - ${String(tag)}`);
lines.push(`category: ${String(ai.category || source.frontmatter.category || 'security')}`);
lines.push(`created_at: ${source.frontmatter.created_at || now}`);
lines.push(`updated_at: ${now}`);
lines.push(`source_type: ${source.frontmatter.source_type || 'note'}`);
lines.push(`source_path: "${String(source.frontmatter.source_path || '/Notes/Blog Articles/1-Review/').replace(/"/g, '\\"')}"`);
lines.push(`summary: "${String(ai.summary || '').replace(/"/g, '\\"')}"`);
lines.push(`excerpt: "${String(ai.excerpt || '').replace(/"/g, '\\"')}"`);
lines.push(`publish_at: ${source.frontmatter.publish_at || 'null'}`);
lines.push(`canonical_url: "${String(source.frontmatter.canonical_url || '').replace(/"/g, '\\"')}"`);
lines.push(`meta_description: "${String(ai.meta_description || '').replace(/"/g, '\\"')}"`);
lines.push(`og_image: "${String(source.frontmatter.og_image || '').replace(/"/g, '\\"')}"`);
lines.push(`review_round: ${reviewRound}`);
lines.push(`published_json_path: "${String(source.frontmatter.published_json_path || '').replace(/"/g, '\\"')}"`);
lines.push('---');
lines.push('');
lines.push(String(ai.body_markdown || source.body_markdown || '').trim());

return {
  json: {
    source_path: source.source_path,
    reviewed_path: source.reviewed_path,
    reviewed_markdown: lines.join('\n')
  }
};
